function solve(nums: number[], queries: number[][]): number {
    const mod = 1000000007;
    const n = nums.length;
    const THRES = Math.floor(Math.sqrt(n));

    const maxV = 100000;
    const inverses = new Array(maxV + 1);
    inverses[0] = 0;

    function modInverse(a: number, modulus: number): number {
        let base = a % modulus;
        let exp = modulus - 2;
        let res = 1;
        while (exp > 0) {
            if (exp & 1) {
                res = (res * base) % modulus;
            }
            base = (base * base) % modulus;
            exp = Math.floor(exp / 2);
        }
        return res;
    }

    for (let i = 1; i <= maxV; i++) {
        inverses[i] = modInverse(i, mod);
    }

    const groups: { l: number; r: number; v: number; }[][][] = [];
    for (let k = 0; k <= THRES; k++) {
        groups[k] = [];
        for (let r = 0; r < k; r++) {
            groups[k][r] = [];
        }
    }

    for (const query of queries) {
        const [l, r, k, v] = query;
        if (k > THRES) {
            for (let j = l; j <= r; j += k) {
                nums[j] = (nums[j] * v) % mod;
            }
        } else if (k >= 1) {
            const residue = l % k;
            groups[k][residue].push({ l, r, v });
        }
    }

    for (let k = 1; k <= THRES; k++) {
        for (let residue = 0; residue < k; residue++) {
            const residueQueries = groups[k][residue];
            if (residueQueries.length === 0) continue;

            const indices: number[] = [];
            for (let j = residue; j < n; j += k) {
                indices.push(j);
            }
            const M = indices.length;
            if (M === 0) continue;

            const events: number[][] = Array.from({ length: M + 10 }, () => []);

            for (const { l, r, v } of residueQueries) {
                const a = Math.floor((l - residue) / k);
                let b = Math.floor((r - residue) / k);

                if (b >= M) b = M - 1;
                if (a > b) continue;

                events[a].push(v);
                events[b + 1].push(inverses[v]);
            }

            let cur = 1;
            for (let i = 0; i < M; i++) {
                for (const factor of events[i]) {
                    cur = (cur * factor) % mod;
                }
                const pos = indices[i];
                nums[pos] = (nums[pos] * cur) % mod;
            }
        }
    }

    let ans = 0;
    for (const num of nums) {
        ans ^= num;
    }
    return ans;
}
