function solve(nums: number[], queries: number[][]): number {
    const n = nums.length;
    const B = Math.floor(Math.sqrt(n));
    const residueClasses: { [key: number]: { list: number[], events: number[] }[] } = {};

    for (let k = 1; k <= B; k++) {
        residueClasses[k] = [];
        for (let r = 0; r < k; r++) {
            residueClasses[k][r] = { list: [], events: [] };
        }
    }

    for (let k = 1; k <= B; k++) {
        for (let i = 0; i < n; i++) {
            const r = i % k;
            residueClasses[k][r].list.push(i);
        }
    }

    for (let k = 1; k <= B; k++) {
        for (let r = 0; r < k; r++) {
            const len = residueClasses[k][r].list.length;
            residueClasses[k][r].events = new Array(len + 1).fill(1);
        }
    }

    function modInverse(a: number, mod: number): number {
        let exp = mod - 2;
        let base = a % mod;
        let res = 1;
        while (exp > 0) {
            if (exp & 1) {
                res = (res * base) % mod;
            }
            base = (base * base) % mod;
            exp = Math.floor(exp / 2);
        }
        return res;
    }

    const arr = [...nums];

    for (const query of queries) {
        const [l, r, k_val, v] = query;
        const vi = v % MOD;
        if (k_val > B) {
            let idx = l;
            while (idx <= r) {
                arr[idx] = (arr[idx] * vi) % MOD;
                idx += k_val;
            }
        } else {
            const r0 = l % k_val;
            const { list, events } = residueClasses[k_val][r0];
            if (list.length === 0) continue;

            let L_index = list.length;
            let low = 0;
            let high = list.length - 1;
            while (low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (list[mid] >= l) {
                    L_index = mid;
                    high = mid - 1;
                } else {
                    low = mid + 1;
                }
            }

            low = 0;
            high = list.length - 1;
            let R_index = -1;
            while (low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (list[mid] <= r) {
                    R_index = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }

            if (L_index > R_index || R_index === -1) continue;

            events[L_index] = (events[L_index] * vi) % MOD;
            if (R_index + 1 < events.length) {
                events[R_index + 1] = (events[R_index + 1] * modInverse(vi, MOD)) % MOD;
            }
        }
    }

    const factor_small = new Array(n).fill(1);

    for (let k_val = 1; k_val <= B; k_val++) {
        for (let r = 0; r < k_val; r++) {
            const { list, events } = residueClasses[k_val][r];
            let current = 1;
            for (let i = 0; i < list.length; i++) {
                current = (current * events[i]) % MOD;
                factor_small[list[i]] = (factor_small[list[i]] * current) % MOD;
            }
        }
    }

    for (let i = 0; i < n; i++) {
        arr[i] = (arr[i] * factor_small[i]) % MOD;
    }

    let result = 0;
    for (const num of arr) {
        result ^= num;
    }
    return result;
