    const smallQueries: number[][][] = new Array(T + 1);
    for (let k = 1; k <= T; k++) {
        smallQueries[k] = Array.from({ length: k }, () => []);
    }

    for (const q of queries) {
        const [l, r, k, v] = q;
        if (k <= T) {
            const residue = l % k;
            smallQueries[k][residue].push([l, r, v]);
        }
    }

    // Process each residue class for small k
    for (let k = 1; k <= T; k++) {
        for (let residue = 0; residue < k; residue++) {
            if (smallQueries[k][residue].length === 0) continue;

            const positions: number[] = [];
            for (let i = residue; i < n; i += k) {
                positions.push(i);
            }
            if (positions.length === 0) continue;

            const size = positions.length;
            const treeSize = 4 * size;
            const seg = new Array(treeSize).fill(1);
            const lazy = new Array(treeSize).fill(1);

            const update = (node: number, start: number, end: number, l: number, r: number, value: number): void => {
                if (start > r || end < l) return;
                if (l <= start && end <= r) {
                    seg[node] = (seg[node] * value) % mod;
                    lazy[node] = (lazy[node] * value) % mod;
                    return;
                }
                const mid = Math.floor((start + end) / 2);
                if (lazy[node] !== 1) {
                    const leftChild = 2 * node + 1;
                    const rightChild = 2 * node + 2;
                    seg[leftChild] = (seg[leftChild] * lazy[node]) % mod;
                    seg[rightChild] = (seg[rightChild] * lazy[node]) % mod;
                    lazy[leftChild] = (lazy[leftChild] * lazy[node]) % mod;
                    lazy[rightChild] = (lazy[rightChild] * lazy[node]) % mod;
                    lazy[node] = 1;
                }
                update(2 * node + 1, start, mid, l, r, value);
                update(2 * node + 2, mid + 1, end, l, r, value);
            };

            const getLeafValue = (node: number, start: number, end: number, index: number): number => {
                if (start === end) {
                    return seg[node];
                }
                const mid = Math.floor((start + end) / 2);
                if (lazy[node] !== 1) {
                    const leftChild = 2 * node + 1;
                    const rightChild = 2 * node + 2;
                    seg[leftChild] = (seg[leftChild] * lazy[node]) % mod;
                    seg[rightChild] = (seg[rightChild] * lazy[node]) % mod;
                    lazy[leftChild] = (lazy[leftChild] * lazy[node]) % mod;
                    lazy[rightChild] = (lazy[rightChild] * lazy[node]) % mod;
                    lazy[node] = 1;
                }
                if (index <= mid) {
                    return getLeafValue(2 * node + 1, start, mid, index);
                } else {
                    return getLeafValue(2 * node + 2, mid + 1, end, index);
                }
            };

            const findFirstGreaterEqual = (x: number): number => {
                let low = 0, high = size - 1;
                while (low <= high) {
                    const mid = Math.floor((low + high) / 2);
                    if (positions[mid] < x) {
                        low = mid + 1;
                    } else {
