    const largeF: number[] = new Array(n).fill(1);
    const smallF: number[][][] = [];

    for (let k = 1; k <= B; k++) {
        smallF[k] = [];
        for (let r = 0; r < k; r++) {
            const len = Math.floor((n - 1 - r) / k) + 1;
            smallF[k][r] = new Array(len).fill(1);
        }
    }

    for (const query of queries) {
        const l = query[0];
        const r_val = query[1];
        const k_val = query[2];
        const v = query[3];

        if (k_val > B) {
            for (let i = l; i <= r_val; i += k_val) {
                largeF[i] = (largeF[i] * v) % MOD;
            }
        } else {
            const residue = l % k_val;
            const j_low = Math.floor((l - residue) / k_val);
            const j_high = Math.floor((r_val - residue) / k_val);

            smallF[k_val][residue][j_low] = (smallF[k_val][residue][j_low] * v) % MOD;
            if (j_high + 1 < smallF[k_val][residue].length) {
                const inv_v = modInverse(v, MOD);
                smallF[k_val][residue][j_high + 1] = (smallF[k_val][residue][j_high + 1] * inv_v) % MOD;
            }
        }
    }

    for (let k = 1; k <= B; k++) {
        for (let r = 0; r < k; r++) {
            const arr = smallF[k][r];
            for (let j = 1; j < arr.length; j++) {
                arr[j] = (arr[j] * arr[j - 1]) % MOD;
            }
        }
    }

    let result = 0;
    for (let i = 0; i < n; i++) {
        let factor = largeF[i];
        for (let k = 1; k <= B; k++) {
            const residue = i % k;
            const j = Math.floor((i - residue) / k);
            if (j < smallF[k][residue].length) {
                factor = (factor * smallF[k][residue][j]) % MOD;
            }
        }
        const value = (nums[i] * factor) % MOD;
        result = result ^ value;
    }

    return result;
}
